mapper.select:
SELECT e.event_seq ,e.title ,e.description AS summary ,e.start_at AS event_start_dt ,e.end_at AS event_end_dt ,COALESCE(e.venue_name, e.venue_address) AS location ,e.status ,CASE WHEN e.deleted_at IS NULL THEN 'Y' ELSE 'N' END AS use_yn ,e.created_at AS rgst_date_time ,e.event_type ,o.name AS organization_name ,e.max_participants ,COALESCE(rc.registration_count, 0) AS registration_count FROM event.events e LEFT JOIN event.organizations o ON o.organization_seq = e.organization_seq LEFT JOIN ( SELECT event_seq, COUNT(*) AS registration_count FROM event.registrations WHERE status NOT IN ('cancelled', 'refunded') GROUP BY event_seq ) rc ON rc.event_seq = e.event_seq
e.deleted_at IS NULL
AND e.status = #{status}
AND e.event_type = #{eventType}
AND ( e.title ILIKE '%' || #{keyword} || '%' OR o.name ILIKE '%' || #{keyword} || '%' )
ORDER BY e.start_at DESC, e.event_seq DESC

mapper.update:
UPDATE event.events
SET  title             = #{title}
    ,description       = #{content}
    ,event_type        = COALESCE(NULLIF(#{eventType}, ''), event_type)
    ,is_paid           = COALESCE(#{isPaid}, is_paid)
    ,file_seq          = #{fileSeq}
    ,attachment_file_seq = #{attachmentFileSeq}
    ,start_at          = #{eventStartDt}
    ,end_at            = #{eventEndDt}
    ,registration_start_at = #{registrationStartDt}
    ,registration_end_at   = #{registrationEndDt}
    ,venue_name        = #{location}
    ,venue_address     = #{venueAddress}
    ,max_participants  = #{maxParticipants}
    ,organization_seq  = #{organizationSeq}
    ,registration_type = COALESCE(NULLIF(#{registrationType,jdbcType=VARCHAR}, ''), registration_type)
    ,registration_url  = #{registrationUrl,jdbcType=VARCHAR}
    ,status            = #{status}
    ,updated_by        = #{uptUserSeq}
    ,updated_at        = CURRENT_TIMESTAMP
WHERE event_seq = #{eventSeq}
  AND deleted_at IS NULL
